}

import { z } from "zod";

export const GeoPointSchema = z.object({
  lat: z.number().min(-90).max(90),
  lng: z.number().min(-180).max(180),
});

export const PersonStatusSchema = z.enum([
  "garrison",
  "tdy",
  "deployed",
  "leave",
  "training",
  "td",
]);

export const EquipmentConditionSchema = z.enum([
  "fully_mission_capable",
  "partially_mission_capable",
  "non_mission_capable",
  "maintenance",
  "unknown",
]);

export const SiteSchema = z.object({
  id: z.string(),
  name: z.string(),
  icao: z.string().optional(),
  country: z.string(),
  timezone: z.string().optional(),
  coordinates: GeoPointSchema,
});

export const PersonSchema = z.object({
  id: z.string(),
  name: z.string(),
  rankRole: z.string(),
  unit: z.string(),
  contactNote: z.string().optional(),
  status: PersonStatusSchema,
  locationLabel: z.string(),
  coordinates: GeoPointSchema,
  siteId: z.string().optional(),
  ordersRemarks: z.string().optional(),
  lastVerifiedAt: z.string(),
});

export const EquipmentSchema = z.object({
  id: z.string(),
  nomenclature: z.string(),
  serialOrId: z.string().optional(),
  custodian: z.string(),
  homeStation: z.string(),
  locationLabel: z.string(),
  coordinates: GeoPointSchema,
  siteId: z.string().optional(),
  condition: EquipmentConditionSchema,
  calibrationDueAt: z.string().optional(),
  accountabilityRef: z.string().optional(),
});

export const EventKindSchema = z.enum([
  "movement",
  "status_change",
  "equipment_condition",
  "note",
]);

export const OpsEventSchema = z.object({
  id: z.string(),
  at: z.string(),
  kind: EventKindSchema,
  summary: z.string(),
  entityType: z.enum(["person", "equipment"]).optional(),
  entityId: z.string().optional(),
  actor: z.string().optional(),
  meta: z.record(z.string(), z.unknown()).optional(),
});

export const OpsDatasetSchema = z.object({
  version: z.literal(1),
  sites: z.array(SiteSchema),
  people: z.array(PersonSchema),
  equipment: z.array(EquipmentSchema),
  events: z.array(OpsEventSchema),
  updatedAt: z.string(),
});

export type GeoPoint = z.infer<typeof GeoPointSchema>;
export type PersonStatus = z.infer<typeof PersonStatusSchema>;
export type EquipmentCondition = z.infer<typeof EquipmentConditionSchema>;
export type Site = z.infer<typeof SiteSchema>;
export type Person = z.infer<typeof PersonSchema>;
export type Equipment = z.infer<typeof EquipmentSchema>;
export type OpsEvent = z.infer<typeof OpsEventSchema>;
export type OpsDataset = z.infer<typeof OpsDatasetSchema>;

import type { OpsDataset, OpsEvent, Person, Equipment } from "./schemas.js";

function parseTime(isoStr: string): number {
  return new Date(isoStr).getTime();
}

/** Events sorted ascending by time */
export function sortEvents(events: OpsEvent[]): OpsEvent[] {
  return [...events].sort((a, b) => parseTime(a.at) - parseTime(b.at));
}

export interface ReplayFrame {
  at: string;
  people: Person[];
  equipment: Equipment[];
}

/**
 * Reconstruct approximate positions at time T using last known state before T from events.
 * MVP heuristic: start from current dataset; walk events after T in reverse... simplified:
 * For prototype we apply movements: each movement event before/at T updates entity location from snapshot in meta if present,
 * else we use seeded initial locations by replaying forward from empty - too heavy.
 *
 * Simpler approach for MVP: store only current state in people/equipment; replay only highlights events up to T on map
 * and keeps current coordinates (demo). Proper implementation would use event-sourced state.
 *
 * Here we replay **forward** from synthetic baselines: clone current entities, sort events ascending,
 * for each event <= T with meta.patch apply patch.
 */
export function buildStateAtTime(dataset: OpsDataset, atIso: string): ReplayFrame {
  const t = parseTime(atIso);
  const people = structuredClone(dataset.people);
  const equipment = structuredClone(dataset.equipment);
  const sorted = sortEvents(dataset.events);

  for (const ev of sorted) {
    if (parseTime(ev.at) > t) break;
    const patch = ev.meta?.patch as
      | { lat?: number; lng?: number; locationLabel?: string }
      | undefined;
    if (ev.entityType === "person" && ev.entityId && patch) {
      const p = people.find((x) => x.id === ev.entityId);
      if (p) {
        if (patch.lat != null && patch.lng != null) {
          p.coordinates = { lat: patch.lat, lng: patch.lng };
        }
        if (patch.locationLabel) p.locationLabel = patch.locationLabel;
      }
    }
    if (ev.entityType === "equipment" && ev.entityId && patch) {
      const e = equipment.find((x) => x.id === ev.entityId);
      if (e) {
        if (patch.lat != null && patch.lng != null) {
          e.coordinates = { lat: patch.lat, lng: patch.lng };
        }
        if (patch.locationLabel) e.locationLabel = patch.locationLabel;
      }
    }
  }

  return { at: atIso, people, equipment };
}

export function latestEventTime(dataset: OpsDataset): number {
  if (dataset.events.length === 0) return Date.now();
  return Math.max(...dataset.events.map((e) => parseTime(e.at)));
}

export function earliestEventTime(dataset: OpsDataset): number {
  if (dataset.events.length === 0) return Date.now();
  return Math.min(...dataset.events.map((e) => parseTime(e.at)));
}

import type { Equipment, OpsDataset, Person } from "./schemas.js";

const STALE_MS = 48 * 60 * 60 * 1000;

export interface AlertItem {
  id: string;
  severity: "warning" | "critical";
  title: string;
  detail: string;
  entityType: "person" | "equipment";
  entityId: string;
}

function isStale(iso: string): boolean {
  return Date.now() - new Date(iso).getTime() > STALE_MS;
}

export function deriveAlerts(dataset: OpsDataset): AlertItem[] {
  const alerts: AlertItem[] = [];
  for (const p of dataset.people) {
    if (isStale(p.lastVerifiedAt)) {
      alerts.push({
        id: `stale-person-${p.id}`,
        severity: "warning",
        title: "Stale personnel verification",
        detail: `${p.name} last verified ${p.lastVerifiedAt}`,
        entityType: "person",
        entityId: p.id,
      });
    }
  }
  for (const e of dataset.equipment) {
    if (e.condition === "non_mission_capable" || e.condition === "maintenance") {
      alerts.push({
        id: `nmc-${e.id}`,
        severity: "critical",
        title: "Equipment not fully capable",
        detail: `${e.nomenclature} — ${e.condition.replaceAll("_", " ")}`,
        entityType: "equipment",
        entityId: e.id,
      });
    }
    if (e.calibrationDueAt && new Date(e.calibrationDueAt).getTime() < Date.now()) {
      alerts.push({
        id: `cal-${e.id}`,
        severity: "warning",
        title: "Calibration overdue",
        detail: `${e.nomenclature} due ${e.calibrationDueAt}`,
        entityType: "equipment",
        entityId: e.id,
      });
    }
    if (!e.custodian || e.custodian.trim() === "") {
      alerts.push({
        id: `cust-${e.id}`,
        severity: "warning",
        title: "Missing custodian",
        detail: e.nomenclature,
        entityType: "equipment",
        entityId: e.id,
      });
    }
  }
  return alerts;
}

export function readinessRollup(equipment: Equipment[]): {
  total: number;
  fmc: number;
  pmc: number;
  nmc: number;
} {
  let fmc = 0;
  let pmc = 0;
  let nmc = 0;
  for (const e of equipment) {
    if (e.condition === "fully_mission_capable") fmc++;
    else if (e.condition === "partially_mission_capable") pmc++;
    else if (e.condition === "non_mission_capable") nmc++;
  }
  return { total: equipment.length, fmc, pmc, nmc };
}

export function personnelByStatus(people: Person[]): Record<string, number> {
  const out: Record<string, number> = {};
  for (const p of people) {
    out[p.status] = (out[p.status] ?? 0) + 1;
  }
  return out;
}

