import { StrictMode } from "react";
import { createRoot } from "react-dom/client";
import { App } from "./App";
import "./index.css";
import { OpsProvider } from "./store/OpsContext";

createRoot(document.getElementById("root")!).render(
  <StrictMode>
    <OpsProvider>
      <App />
    </OpsProvider>
  </StrictMode>,
);

import {
  type OpsDataset,
  type Person,
  type Equipment,
  type Site,
  createSeedDataset,
  loadDatasetFromLocalStorage,
  saveDatasetToLocalStorage,
  earliestEventTime,
  latestEventTime,
  buildStateAtTime,
  OpsEventSchema,
  type OpsEvent,
} from "@comm-ops/core";
import {
  createContext,
  useCallback,
  useContext,
  useEffect,
  useMemo,
  useState,
  type ReactNode,
} from "react";

export type MapLayers = {
  people: boolean;
  equipment: boolean;
  sites: boolean;
};

export type Selection =
  | { kind: "person"; id: string }
  | { kind: "equipment"; id: string }
  | { kind: "site"; id: string }
  | null;

type OpsCtx = {
  dataset: OpsDataset;
  setDataset: (d: OpsDataset) => void;
  replayTimeMs: number | null;
  setReplayTimeMs: (t: number | null) => void;
  replayBounds: { min: number; max: number };
  effectivePeople: Person[];
  effectiveEquipment: Equipment[];
  layers: MapLayers;
  setLayers: React.Dispatch<React.SetStateAction<MapLayers>>;
  selection: Selection;
  setSelection: (s: Selection) => void;
  importJson: (raw: string) => void;
  exportJson: () => string;
  resetToSeed: () => void;
  pickMode: boolean;
  setPickMode: (v: boolean) => void;
  mapPickTarget: { kind: "person" | "equipment"; id: string } | null;
  setMapPickTarget: (v: { kind: "person" | "equipment"; id: string } | null) => void;
  addEvent: (e: Omit<OpsEvent, "id"> & { id?: string }) => void;
  upsertPerson: (p: Person) => void;
  upsertEquipment: (e: Equipment) => void;
  deletePerson: (id: string) => void;
  deleteEquipment: (id: string) => void;
};

const Ctx = createContext<OpsCtx | null>(null);

function bumpUpdated(ds: OpsDataset): OpsDataset {
  return { ...ds, updatedAt: new Date().toISOString() };
}

export function OpsProvider({ children }: { children: ReactNode }) {
  const [dataset, setDatasetState] = useState<OpsDataset>(() => {
    const stored = typeof localStorage !== "undefined" ? loadDatasetFromLocalStorage() : null;
    return stored ?? createSeedDataset();
  });
  const [replayTimeMs, setReplayTimeMs] = useState<number | null>(null);
  const [layers, setLayers] = useState<MapLayers>({ people: true, equipment: true, sites: true });
  const [selection, setSelection] = useState<Selection>(null);
  const [pickMode, setPickMode] = useState(false);
  const [mapPickTarget, setMapPickTarget] = useState<{ kind: "person" | "equipment"; id: string } | null>(
    null,
  );

  const replayBounds = useMemo(() => {
    const min = earliestEventTime(dataset);
    const max = Math.max(latestEventTime(dataset), Date.now());
    return { min, max };
  }, [dataset]);

  const replayIso = replayTimeMs != null ? new Date(replayTimeMs).toISOString() : null;
  const replayFrame = useMemo(() => {
    if (!replayIso) return null;
    return buildStateAtTime(dataset, replayIso);
  }, [dataset, replayIso]);

  const effectivePeople = replayFrame?.people ?? dataset.people;
  const effectiveEquipment = replayFrame?.equipment ?? dataset.equipment;

  const setDataset = useCallback((d: OpsDataset) => {
    const next = bumpUpdated(d);
    setDatasetState(next);
    saveDatasetToLocalStorage(next);
  }, []);

  useEffect(() => {
    saveDatasetToLocalStorage(dataset);
  }, [dataset]);

  const importJson = useCallback(
    (raw: string) => {
      const data = JSON.parse(raw) as unknown;
      const { OpsDatasetSchema: Schema } = require("@comm-ops/core") as typeof import("@comm-ops/core");
      const parsed = Schema.parse(data);
      setDataset(parsed);
      setReplayTimeMs(null);
    },
    [setDataset],
  );

  const exportJson = useCallback(() => JSON.stringify(dataset, null, 2), [dataset]);

  const resetToSeed = useCallback(() => {
    setDataset(createSeedDataset());
    setReplayTimeMs(null);
    setSelection(null);
  }, [setDataset]);

  const addEvent = useCallback(
    (e: Omit<OpsEvent, "id"> & { id?: string }) => {
      const id = e.id ?? `ev-${crypto.randomUUID()}`;
      const full = OpsEventSchema.parse({ ...e, id });
      setDataset({ ...dataset, events: [...dataset.events, full] });
    },
    [dataset, setDataset],
  );

  const upsertPerson = useCallback(
    (p: Person) => {
      const idx = dataset.people.findIndex((x) => x.id === p.id);
      const people =
        idx === -1 ? [...dataset.people, p] : dataset.people.map((x) => (x.id === p.id ? p : x));
      setDataset({ ...dataset, people });
    },
    [dataset, setDataset],
  );

  const upsertEquipment = useCallback(
    (eq: Equipment) => {
      const idx = dataset.equipment.findIndex((x) => x.id === eq.id);
      const equipment =
        idx === -1
          ? [...dataset.equipment, eq]
          : dataset.equipment.map((x) => (x.id === eq.id ? eq : x));
      setDataset({ ...dataset, equipment });
    },
    [dataset, setDataset],
  );

  const deletePerson = useCallback(
    (id: string) => {
      setDataset({ ...dataset, people: dataset.people.filter((p) => p.id !== id) });
      if (selection?.kind === "person" && selection.id === id) setSelection(null);
    },
    [dataset, setDataset, selection],
  );

  const deleteEquipment = useCallback(
    (id: string) => {
      setDataset({ ...dataset, equipment: dataset.equipment.filter((e) => e.id !== id) });
      if (selection?.kind === "equipment" && selection.id === id) setSelection(null);
    },
    [dataset, setDataset, selection],
  );

  const value: OpsCtx = {
    dataset,
    setDataset,
    replayTimeMs,
    setReplayTimeMs,
    replayBounds,
    effectivePeople,
    effectiveEquipment,
    layers,
    setLayers,
    selection,
    setSelection,
    importJson,
    exportJson,
    resetToSeed,
    pickMode,
    setPickMode,
    mapPickTarget,
    setMapPickTarget,
    addEvent,
    upsertPerson,
    upsertEquipment,
    deletePerson,
    deleteEquipment,
  };

  return <Ctx.Provider value={value}>{children}</Ctx.Provider>;
}

export function useOps() {
  const v = useContext(Ctx);
  if (!v) throw new Error("useOps requires OpsProvider");
  return v;
}

export function siteById(sites: Site[], id?: string) {
  if (!id) return undefined;
  return sites.find((s) => s.id === id);
}

