import { sortEvents } from "@comm-ops/core";
import { motion } from "framer-motion";
import { Pause, Play, SkipForward } from "lucide-react";
import { useEffect, useMemo, useRef, useState } from "react";
import { useOps } from "../store/OpsContext";

export function Timeline() {
  const {
    dataset,
    replayTimeMs,
    setReplayTimeMs,
    replayBounds,
    setSelection,
  } = useOps();
  const sorted = useMemo(() => sortEvents(dataset.events), [dataset.events]);
  const [playing, setPlaying] = useState(false);
  const rafRef = useRef<number | null>(null);

  useEffect(() => {
    if (replayTimeMs == null) {
      setReplayTimeMs(replayBounds.max);
    }
  }, [replayTimeMs, replayBounds.max, setReplayTimeMs]);

  useEffect(() => {
    if (!playing || replayTimeMs == null) return;
    const start = performance.now();
    const from = replayTimeMs;
    const span = 120_000;
    const deltaTarget = replayBounds.max - from;

    const tick = (now: number) => {
      const t = (now - start) / span;
      const next = from + t * deltaTarget;
      if (next >= replayBounds.max) {
        setReplayTimeMs(replayBounds.max);
        setPlaying(false);
        return;
      }
      setReplayTimeMs(next);
      rafRef.current = requestAnimationFrame(tick);
    };
    rafRef.current = requestAnimationFrame(tick);
    return () => {
      if (rafRef.current) cancelAnimationFrame(rafRef.current);
    };
  }, [playing, replayTimeMs, replayBounds.max, replayBounds.min, setReplayTimeMs]);

  const scrubValue = replayTimeMs ?? replayBounds.max;
  const progress =
    replayBounds.max === replayBounds.min
      ? 1
      : (scrubValue - replayBounds.min) / (replayBounds.max - replayBounds.min);

  return (
    <div className="panel" style={{ display: "flex", flexDirection: "column", gap: 10, padding: 12 }}>
      <div className="panel-header" style={{ border: "none", padding: "0 0 4px" }}>
        Timeline
      </div>
      <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
        <button
          type="button"
          className="btn"
          aria-label={playing ? "Pause" : "Play"}
          onClick={() => setPlaying((p) => !p)}
        >
          {playing ? <Pause size={16} /> : <Play size={16} />}
        </button>
        <button
          type="button"
          className="btn"
          aria-label="Live now"
          onClick={() => {
            setPlaying(false);
            setReplayTimeMs(null);
          }}
        >
          <SkipForward size={16} />
        </button>
        <span className="chip" style={{ marginLeft: "auto" }}>
          {replayTimeMs == null ? "LIVE" : new Date(scrubValue).toLocaleString()}
        </span>
      </div>
      <input
        type="range"
        className="range"
        min={0}
        max={1000}
        step={1}
        value={Math.round(progress * 1000)}
        onChange={(e) => {
          setPlaying(false);
          const p = Number(e.target.value) / 1000;
          const ms = replayBounds.min + p * (replayBounds.max - replayBounds.min);
          setReplayTimeMs(ms);
        }}
      />
      <div className="scroll-y" style={{ maxHeight: 200 }}>
        {sorted
          .slice()
          .reverse()
          .map((ev) => {
            const active = replayTimeMs != null && new Date(ev.at).getTime() <= scrubValue;
            return (
              <motion.button
                type="button"
                key={ev.id}
                onClick={() => {
                  setPlaying(false);
                  setReplayTimeMs(new Date(ev.at).getTime());
                  if (ev.entityType === "person" && ev.entityId) { setSelection({ kind: "person", id: ev.entityId }); }
                  else if (ev.entityType === "equipment" && ev.entityId) setSelection({ kind: "equipment", id: ev.entityId });
                }}
                initial={false}
                animate={{ opacity: active ? 1 : 0.45 }}
                style={{
                  width: "100%",
                  textAlign: "left",
                  padding: "8px 10px",
                  borderRadius: "var(--radius)",
                  border: "1px solid var(--border)",
                  background: active ? "rgba(94,234,255,0.07)" : "transparent",
                  marginBottom: 6,
                }}
              >
                <div style={{ fontSize: 10, color: "var(--text-dim)", letterSpacing: "0.08em" }}>
                  {new Date(ev.at).toLocaleString()} · {ev.kind}
                </div>
                <div style={{ fontSize: 12, marginTop: 4 }}>{ev.summary}</div>
              </motion.button>
            );
          })}
      </div>
    </div>
  );
}

import { deriveAlerts, readinessRollup, personnelByStatus } from "@comm-ops/core";
import { Download } from "lucide-react";
import { useMemo, useState } from "react";
import { useOps } from "../store/OpsContext";

function downloadCsv(filename: string, rows: string[][]) {
  const esc = (c: string) => `"${c.replaceAll('"', '""')}"`;
  const body = rows.map((r) => r.map(esc).join(",")).join("\n");
  const blob = new Blob([body], { type: "text/csv;charset=utf-8" });
  const url = URL.createObjectURL(blob);
  const a = document.createElement("a");
  a.href = url;
  a.download = filename;
  a.click();
  URL.revokeObjectURL(url);
}

export function Boards() {
  const { dataset, effectivePeople, effectiveEquipment, setSelection } = useOps();
  const alerts = useMemo(() => deriveAlerts(dataset), [dataset]);
  const rollup = useMemo(() => readinessRollup(effectiveEquipment), [effectiveEquipment]);
  const statusCounts = useMemo(() => personnelByStatus(effectivePeople), [effectivePeople]);

  const [personFilter, setPersonFilter] = useState("");
  const [equipFilter, setEquipFilter] = useState("");

  const peopleRows = effectivePeople.filter(
    (p) =>
      !personFilter ||
      `${p.name} ${p.unit} ${p.status} ${p.locationLabel}`.toLowerCase().includes(
        personFilter.toLowerCase(),
      ),
  );
  const equipRows = effectiveEquipment.filter(
    (e) =>
      !equipFilter ||
      `${e.nomenclature} ${e.custodian} ${e.condition} ${e.locationLabel}`
        .toLowerCase()
        .includes(equipFilter.toLowerCase()),
  );

  return (
    <div style={{ display: "grid", gap: 12 }}>
      <div className="panel">
        <div className="panel-header">Readiness roll-up</div>
        <div style={{ padding: 12, display: "grid", gridTemplateColumns: "repeat(4, 1fr)", gap: 8 }}>
          <Stat label="Equipment" value={String(rollup.total)} />
          <Stat label="FMC" value={String(rollup.fmc)} tone="ok" />
          <Stat label="PMC" value={String(rollup.pmc)} tone="warn" />
          <Stat label="NMC" value={String(rollup.nmc)} tone="bad" />
        </div>
        <div style={{ padding: "0 12px 12px", fontSize: 12, color: "var(--text-dim)" }}>
          Personnel by status:{" "}
          {Object.entries(statusCounts)
            .map(([k, v]) => `${k}: ${v}`)
            .join(" · ")}
        </div>
      </div>

      <div className="panel">
        <div className="panel-header">Exceptions</div>
        <div className="scroll-y" style={{ maxHeight: 160, padding: 8 }}>
          {alerts.length === 0 && (
            <div style={{ padding: 8, fontSize: 13, color: "var(--text-dim)" }}>No derived alerts.</div>
          )}
          {alerts.map((a) => (
            <button
              key={a.id}
              type="button"
              className="btn"
              style={{
                width: "100%",
                justifyContent: "flex-start",
                marginBottom: 6,
                borderColor: a.severity === "critical" ? "var(--danger)" : "var(--warn)",
              }}
              onClick={() => setSelection({ kind: a.entityType, id: a.entityId })}
            >
              <div style={{ textAlign: "left" }}>
                <div style={{ fontWeight: 700, fontSize: 12 }}>{a.title}</div>
                <div style={{ fontSize: 11, color: "var(--text-dim)", marginTop: 4 }}>{a.detail}</div>
              </div>
            </button>
          ))}
        </div>
      </div>

      <div className="panel">
        <div className="panel-header" style={{ gap: 8 }}>
          <span>Roster</span>
          <button
            type="button"
            className="btn"
            style={{ marginLeft: "auto" }}
            onClick={() =>
              downloadCsv("roster.csv", [
                ["name", "rankRole", "unit", "status", "location", "lastVerified"],
                ...peopleRows.map((p) => [
                  p.name,
                  p.rankRole,
                  p.unit,
                  p.status,
                  p.locationLabel,
                  p.lastVerifiedAt,
                ]),
              ])
            }
          >
            <Download size={14} /> CSV
          </button>
        </div>
        <div style={{ padding: 8 }}>
          <input
            className="input"
            placeholder="Filter roster…"
            value={personFilter}
            onChange={(e) => setPersonFilter(e.target.value)}
          />
        </div>
        <div className="scroll-y" style={{ maxHeight: 280 }}>
          <table className="table">
            <thead>
              <tr>
                <th>Name</th>
                <th>Unit</th>
                <th>Status</th>
                <th>Location</th>
              </tr>
            </thead>
            <tbody>
              {peopleRows.map((p) => (
                <tr key={p.id} style={{ cursor: "pointer" }} onClick={() => setSelection({ kind: "person", id: p.id })}>
                  <td>{p.name}</td>
                  <td>{p.unit}</td>
                  <td>{p.status}</td>
                  <td>{p.locationLabel}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      <div className="panel">
        <div className="panel-header" style={{ gap: 8 }}>
          <span>Equipment</span>
          <button
            type="button"
            className="btn"
            style={{ marginLeft: "auto" }}
            onClick={() =>
              downloadCsv("equipment.csv", [
                ["nomenclature", "custodian", "homeStation", "condition", "location", "calDue"],
                ...equipRows.map((e) => [
                  e.nomenclature,
                  e.custodian,
                  e.homeStation,
                  e.condition,
                  e.locationLabel,
                  e.calibrationDueAt ?? "",
                ]),
              ])
            }
          >
            <Download size={14} /> CSV
          </button>
        </div>
        <div style={{ padding: 8 }}>
          <input
            className="input"
            placeholder="Filter equipment…"
            value={equipFilter}
            onChange={(e) => setEquipFilter(e.target.value)}
          />
        </div>
        <div className="scroll-y" style={{ maxHeight: 280 }}>
          <table className="table">
            <thead>
              <tr>
                <th>Item</th>
                <th>Custodian</th>
                <th>Condition</th>
                <th>Location</th>
              </tr>
            </thead>
            <tbody>
              {equipRows.map((e) => (
                <tr
                  key={e.id}
                  style={{ cursor: "pointer" }}
                  onClick={() => setSelection({ kind: "equipment", id: e.id })}
                >
                  <td>{e.nomenclature}</td>
                  <td>{e.custodian}</td>
                  <td>{e.condition}</td>
                  <td>{e.locationLabel}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
}

function Stat({ label, value, tone }: { label: string; value: string; tone?: "ok" | "warn" | "bad" }) {
  const color =
    tone === "ok" ? "var(--ok)" : tone === "warn" ? "var(--warn)" : tone === "bad" ? "var(--danger)" : "var(--text)";
  return (
    <div className="panel" style={{ padding: 10, background: "var(--bg-panel-2)" }}>
      <div style={{ fontSize: 10, color: "var(--text-dim)", letterSpacing: "0.08em" }}>{label}</div>
      <div style={{ fontSize: 22, fontWeight: 700, marginTop: 6, color }}>{value}</div>
    </div>
  );
}

