      unit: "",
      status: "garrison",
      locationLabel: "",
      coordinates: { lat: 0, lng: 0 },
      lastVerifiedAt: new Date().toISOString(),
    });

  const blankEquipment = (): Equipment =>
    EquipmentSchema.parse({
